// ── Custom cursor ──────────────────────────────────────
const cursor = document.getElementById('cursor');
document.addEventListener('mousemove', e => {
  cursor.style.left = e.clientX + 'px';
  cursor.style.top  = e.clientY + 'px';
});
document.querySelectorAll('a, .project-card').forEach(el => {
  el.addEventListener('mouseenter', () => cursor.classList.add('big'));
  el.addEventListener('mouseleave', () => cursor.classList.remove('big'));
});

// ── Scroll reveal ──────────────────────────────────────
const observer = new IntersectionObserver(entries => {
  entries.forEach(e => {
    if (e.isIntersecting) { e.target.classList.add('visible'); }
  });
}, { threshold: 0.12 });
document.querySelectorAll('.reveal').forEach(el => observer.observe(el));

// ── p5.js: repelling × grid (your exact aesthetic) ────
new p5(function(p) {
  const COUNT  = 800;
  const COLS   = 35;
  const ROWS   = 22;
  const R_RAD  = 90;
  const R_STR  = 7;
  const RETURN = 0.06;
  let xs = [];

  p.setup = function() {
    const cnv = p.createCanvas(p.windowWidth, p.windowHeight);
    cnv.parent('p5-bg');
    // Override the canvas placement — it IS the bg element
    document.getElementById('p5-bg').replaceWith(cnv.elt);
    cnv.elt.id = 'p5-bg';
    p.textFont('monospace');
    p.textSize(14);
    p.textAlign(p.CENTER, p.CENTER);
    init();
  };

  function init() {
    xs = [];
    const padX = p.width  / COLS;
    const padY = p.height / ROWS;
    for (let i = 0; i < COUNT; i++) {
      const col = i % COLS;
      const row = Math.floor(i / COLS);
      const ox  = padX * 0.5 + col * padX;
      const oy  = padY * 0.5 + row * padY;
      xs.push({ ox, oy, x: ox, y: oy, vx: 0, vy: 0 });
    }
  }

  p.draw = function() {
    p.background(10, 10, 10, 28);
    const mx = p.mouseX, my = p.mouseY;
    for (const x of xs) {
      const dx = x.x - mx, dy = x.y - my;
      const d  = Math.sqrt(dx*dx + dy*dy);
      if (d < R_RAD && d > 0) {
        const f = (R_RAD - d) / R_RAD;
        x.vx += (dx/d) * f * R_STR;
        x.vy += (dy/d) * f * R_STR;
      }
      x.vx += (x.ox - x.x) * RETURN;
      x.vy += (x.oy - x.y) * RETURN;
      x.vx *= 0.80; x.vy *= 0.80;
      x.x  += x.vx;  x.y  += x.vy;
      p.fill(255, 72, 0, 30);
      p.noStroke();
      p.text('×', x.x, x.y);
    }
  };

  p.windowResized = function() {
    p.resizeCanvas(p.windowWidth, p.windowHeight);
    init();
  };
});

