// ── Physics cards ──────────────────────────────────────
const CARDS = [
  { src: "data:image/jpeg;base64,", title: "New Years Party", tag: "Event Design · Print · Typography", imgStyle: "object-fit:cover", num: "01" },
  { src: "data:image/jpeg;base64,", title: "Itoko Menu", tag: "Restaurant Identity · Layout · Print", imgStyle: "object-fit:cover", num: "02" },
  { src: "data:image/jpeg;base64,", title: "Grace's 20th", tag: "Illustration · Invitation · Print", imgStyle: "object-fit:cover", num: "03" },
  { src: "data:image/png;base64,", title: "Bedbug", tag: "Logo Design · Lettering · Brand Identity", imgStyle: "object-fit:contain; background:#000; padding:1rem", num: "04" },
];

const stage = document.getElementById('physics-stage');
const W = () => stage.offsetWidth;
const H = () => stage.offsetHeight;

const hint = document.createElement('div');
hint.id = 'throw-hint';
hint.textContent = 'Drag & throw the cards';
stage.appendChild(hint);

const state = CARDS.map((c, i) => ({
  el: null,
  x: 0, y: 0,
  vx: 0, vy: 0,
  rot: 0, vrot: 0,
  dragging: false,
  mx: 0, my: 0,
  pmx: 0, pmy: 0,
  ox: 0, oy: 0,
  zIndex: i + 1
}));

// Create card elements
CARDS.forEach((c, i) => {
  const el = document.createElement('div');
  el.className = 'pcard';
  el.innerHTML = `
    <img src="${c.src}" alt="${c.title}" style="${c.imgStyle}">
    <div class="pcard-info">
      <div class="pcard-num">${c.num}</div>
      <div class="pcard-title">${c.title}</div>
      <div class="pcard-tag">${c.tag}</div>
    </div>`;
  stage.appendChild(el);
  state[i].el = el;

  // Scatter initial positions
  const angle = (i / CARDS.length) * Math.PI * 2;
  state[i].x = W() * 0.5 + Math.cos(angle) * W() * 0.22 - 140;
  state[i].y = H() * 0.5 + Math.sin(angle) * H() * 0.18 - 160;
  state[i].rot = (Math.random() - 0.5) * 18;
  state[i].vx  = (Math.random() - 0.5) * 3;
  state[i].vy  = (Math.random() - 0.5) * 3;
  apply(i);

  // Drag events
  el.addEventListener('mousedown', e => startDrag(e, i));
  el.addEventListener('touchstart', e => startDrag(e, i), {passive: false});
});

let topZ = CARDS.length;

function startDrag(e, i) {
  e.preventDefault();
  hint.style.opacity = '0';
  topZ++;
  state[i].zIndex = topZ;
  state[i].dragging = true;
  state[i].vx = 0; state[i].vy = 0; state[i].vrot = 0;
  const pt = e.touches ? e.touches[0] : e;
  state[i].ox = pt.clientX - stage.getBoundingClientRect().left - state[i].x;
  state[i].oy = pt.clientY - stage.getBoundingClientRect().top  - state[i].y;
  state[i].pmx = pt.clientX;
  state[i].pmy = pt.clientY;
  state[i].mx  = pt.clientX;
  state[i].my  = pt.clientY;
}

document.addEventListener('mousemove', e => onMove(e));
document.addEventListener('touchmove', e => onMove(e), {passive: false});
function onMove(e) {
  const pt = e.touches ? e.touches[0] : e;
  state.forEach((s, i) => {
    if (!s.dragging) return;
    s.pmx = s.mx; s.pmy = s.my;
    s.mx  = pt.clientX; s.my  = pt.clientY;
    const rect = stage.getBoundingClientRect();
    s.x = pt.clientX - rect.left - s.ox;
    s.y = pt.clientY - rect.top  - s.oy;
    apply(i);
  });
}

document.addEventListener('mouseup',   () => stopDrag());
document.addEventListener('touchend',  () => stopDrag());
function stopDrag() {
  state.forEach((s, i) => {
    if (!s.dragging) return;
    s.dragging = false;
    s.vx    = (s.mx - s.pmx) * 0.8;
    s.vy    = (s.my - s.pmy) * 0.8;
    s.vrot  = s.vx * 0.4;
  });
}

function apply(i) {
  const s = state[i];
  s.el.style.transform = `translate(${s.x}px, ${s.y}px) rotate(${s.rot}deg)`;
  s.el.style.zIndex = s.zIndex;
}

const FRICTION = 0.91;
const BOUNCE   = -0.55;

function loop() {
  state.forEach((s, i) => {
    if (s.dragging) return;
    s.vx   *= FRICTION; s.vy  *= FRICTION; s.vrot *= FRICTION;
    s.x    += s.vx;     s.y   += s.vy;     s.rot  += s.vrot;
    const cw = s.el.offsetWidth  || 280;
    const ch = s.el.offsetHeight || 370;
    const stW = W(), stH = H();
    if (s.x < 0)          { s.x = 0;          s.vx   *= BOUNCE; s.vrot *= -0.5; }
    if (s.x > stW - cw)   { s.x = stW - cw;   s.vx   *= BOUNCE; s.vrot *= -0.5; }
    if (s.y < 0)          { s.y = 0;           s.vy   *= BOUNCE; s.vrot *= -0.5; }
    if (s.y > stH - ch)   { s.y = stH - ch;    s.vy   *= BOUNCE; s.vrot *= -0.5; }
    apply(i);
  });
  requestAnimationFrame(loop);
}
loop();

// ─────────────────────────────────────────────

// ── Lightbox ───────────────────────────────────────────
const lb         = document.getElementById('lightbox');
const lbImg      = document.getElementById('lightbox-img');
const lbNum      = document.getElementById('lightbox-num');
const lbTitle    = document.getElementById('lightbox-title');
const lbTag      = document.getElementById('lightbox-tag');
const lbClose    = document.getElementById('lightbox-close');
const lbBackdrop = document.getElementById('lightbox-backdrop');

let isDragged = false;

// Track if the mousedown → mouseup was a drag or a click
document.querySelectorAll('.pcard').forEach((el, i) => {
  let startX, startY;
  el.addEventListener('mousedown', e => { startX = e.clientX; startY = e.clientY; });
  el.addEventListener('mouseup', e => {
    const dist = Math.hypot(e.clientX - startX, e.clientY - startY);
    if (dist < 6) openLightbox(i);
  });
  el.addEventListener('touchstart', e => { startX = e.touches[0].clientX; startY = e.touches[0].clientY; }, {passive:true});
  el.addEventListener('touchend', e => {
    const t = e.changedTouches[0];
    const dist = Math.hypot(t.clientX - startX, t.clientY - startY);
    if (dist < 10) openLightbox(i);
  });
});


// ── Arrow navigation ───────────────────────────────────
let currentIdx = 0;

function openLightbox(i) {
  currentIdx = i;
  showCard(i);
  lb.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function showCard(i) {
  const c = CARDS[i];
  // Animate out → in
  const card = document.getElementById('lightbox-card');
  card.style.transition = 'none';
  card.style.opacity = '0';
  card.style.transform = 'scale(0.95) translateY(10px)';
  requestAnimationFrame(() => {
    lbImg.src             = c.src;
    lbImg.style.cssText   = c.imgStyle;
    lbNum.textContent     = c.num;
    lbTitle.textContent   = c.title;
    lbTag.textContent     = c.tag;
    document.getElementById('lightbox-counter').textContent = (i+1) + ' / ' + CARDS.length;
    requestAnimationFrame(() => {
      card.style.transition = 'opacity 0.25s ease, transform 0.35s cubic-bezier(0.16,1,0.3,1)';
      card.style.opacity = '1';
      card.style.transform = 'scale(1) translateY(0)';
    });
  });
}

document.getElementById('lb-prev').addEventListener('click', e => {
  e.stopPropagation();
  currentIdx = (currentIdx - 1 + CARDS.length) % CARDS.length;
  showCard(currentIdx);
});
document.getElementById('lb-next').addEventListener('click', e => {
  e.stopPropagation();
  currentIdx = (currentIdx + 1) % CARDS.length;
  showCard(currentIdx);
});
document.addEventListener('keydown', e => {
  if (!lb.classList.contains('open')) return;
  if (e.key === 'ArrowLeft')  { currentIdx = (currentIdx - 1 + CARDS.length) % CARDS.length; showCard(currentIdx); }
  if (e.key === 'ArrowRight') { currentIdx = (currentIdx + 1) % CARDS.length; showCard(currentIdx); }
});


function closeLightbox() {
  lb.classList.remove('open');
  document.body.style.overflow = '';
}

lbClose.addEventListener('click', closeLightbox);
lbBackdrop.addEventListener('click', closeLightbox);
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeLightbox(); });

// ─────────────────────────────────────────────

// ── Flip word ──────────────────────────────────────────
const flipWords = ['you.', 'me.', 'us.', 'them.', 'here.', 'now.', 'real.', 'fun.', 'people.'];
let flipIdx = 0;
const flipEl = document.getElementById('flip-word');

function nextWord() {
  flipEl.classList.remove('flip-in');
  flipEl.classList.add('flip-out');
  setTimeout(() => {
    flipIdx = (flipIdx + 1) % flipWords.length;
    flipEl.textContent = flipWords[flipIdx];
    flipEl.classList.remove('flip-out');
    flipEl.classList.add('flip-in');
  }, 240);
}

setInterval(nextWord, 1800);